sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, a) {
    if (isLoading) {
        return;
    }

    // Get values directly from the form
    var degreeLevel = g_form.getValue('u_degree_level');
    var obtained = parseFloat(g_form.getValue('u_obtained_marks')) || 0;
    var total = parseFloat(g_form.getValue('u_total_marks')) || 0;
    var cgpa = parseFloat(g_form.getValue('u_cgpa')) || 0;

    var finalPercentage = 0.0;

    // Calculate logic
    if (degreeLevel == 'bachelor_s' || degreeLevel == 'master_s') {
        if (cgpa > 0 && cgpa <= 4.0) {
            finalPercentage = (cgpa / 4.0) * 100;
        }
    } else {
        if (total > 0) {
            finalPercentage = (obtained / total) * 100;
        }
    }

    // Set the calculated value back to the Percentage field
    g_form.setValue('u_percentage', finalPercentage.toFixed(2));
}
